	r.Route("/api/assinatura-digital/convites", func(r chi.Router) {
		r.Use(mw.AuditModule(db, "/api/assinatura-digital/convites", "assinatura-digital"))
		r.Use(mw.RateLimit(30, 5*time.Minute))
		r.Get("/{token}", assD.ObterConvite)
		r.With(mw.RateLimit(5, 10*time.Minute)).Post("/{token}/otp/enviar", assD.EnviarOTP)
		r.Post("/{token}/otp/validar", assD.ValidarOTP)
		r.Post("/{token}/assinar", assD.AssinarViaConvite)
		r.Post("/{token}/recusar", assD.RecusarViaConvite)
		r.With(mw.RateLimit(30, 5*time.Minute)).Get("/{token}/preview", assD.PreviewDocumentoConvite)
	})

